var e=[{id:`L2_1`,type:`dialog`,speaker:`AURA_ADMIN_NULL_BODY`,text:{KOREA:`오러 선생님 없인 아무것도 아닌 절 이렇게까지 높이 사주시다니… 고마워요.`,JPN:`オーラ先生無しではなんの力もない私でしたがこれほどまで高く買ってくださるなんて……感謝しています。`,ENG:`Thank you... for thinking so highly of me, even if I'm nothing without Ms. Aura. `,TWN:`沒有奧蘿師父的話，我什麼都不是。謝謝你…這麼看得起我。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`AURA_ADMIN_NULL_BODY`,face:`UNIT_PRIDE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`AURA_ADMIN_NULL_BODY`,text:{KOREA:`수행의 일환으로 캄파멘토의 용병회사에서 탐험가 호위 임무를 맡고 있으니, 들를 일이 생기면 꼭 저를 찾아주세요, 종자여.`,JPN:`修行の一環としてカンパメントの傭兵会社で探検家の護衛任務についているので、立ち寄ることがあればぜひ私に会いに来てください、従者よ。`,ENG:`As part of my training, I am in charge of escorting explorers at a mercenary company in Campamento. If you are ever to stop by, please ask for me, Squire.`,TWN:`我現在在坎帕門托的一家傭兵公司負責保護探險家，就當作是修行的一部分，你有路過的話記得來找我喔，手下。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`AURA_ADMIN_NULL_BODY`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};